// LeadSpecification.java
public class LeadSpecification {
    public static Specification<Lead> hasStatus(LeadStatus status) {
        return (root, query, cb) -> status == null ? null : cb.equal(root.get("status"), status);
    }
    public static Specification<Lead> assignedTo(String user) {
        return (root, query, cb) -> user == null ? null : cb.equal(root.get("assignedTo"), user);
    }
    public static Specification<Lead> createdAfter(LocalDate date) {
        return (root, query, cb) -> date == null ? null : cb.greaterThanOrEqualTo(root.get("createdAt"), date.atStartOfDay());
    }
}

