@Service
public class InventoryBatchService {
    @Transactional
    public void batchUpdateStock(List<StockUpdate> updates) {
        for (int i = 0; i < updates.size(); i++) {
            StockUpdate u = updates.get(i);
            stockRepository.updateQuantity(u.getProductId(), u.getWarehouseId(), u.getQuantity());
            if (i > 0 && i % 50 == 0) {
                entityManager.flush();
                entityManager.clear();
            }
        }
    }
}

